var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아. 이걸로 한 마리 더 잡았네.","JPN":"よし、これで1匹追加ね。","ENG":"Good. That's one more down.","TWN":"太棒了，又消滅了一隻。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"대단해! 역시 우리 소대장이야!","JPN":"すごい！　さすが小隊長！","ENG":"That was amazing! You're the best, Commander!","TWN":"真厲害！不愧是我們的小隊長！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"나, 나도 동감이야. 미나는 정말 실력이 대단하구나......","JPN":"ど、同感だよ。ミナは本当に強いんだね……","ENG":"I-I agree. You're very impressive, Mina...","TWN":"我、我也同意。米娜的實力真強……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잠시 실례할게요. 여기가 미나 소대인가요?","JPN":"あの、失礼します。ミナ小隊ですか？","ENG":"Excuse me. Is this the Mina Squad?","TWN":"打擾一下，這裡是米娜小隊嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 회장님! 제대로 찾아 오셨어요!","JPN":"あっ、会長！　はい、こちらです！","ENG":"Oh, Ms. President! It sure is!","TWN":"啊，會長！你來了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니야! 그 이름으로 부르지 말라고 했잖아!","JPN":"ねえ、その呼び方は勘弁して？","ENG":"No, it's not! I told you to stop calling us that name!","TWN":"喂！都說不要用那個名稱了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어......? 학생회장?","JPN":"あれ……？　生徒会長？","ENG":"Huh? YOU'RE the Student President?","TWN":"呃……？學生會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"역시, 이름이 익숙하다고 생각했는데 블루로즈 섬에서 만났던 분이군요.","JPN":"やはり。聞き覚えのある名前だと思ったら、ブルーローズ島でお会いした方ですね。","ENG":"No wonder the name sounded familiar. We once met on Blue Rose Island.","TWN":"果然，就覺得名字有些熟悉，原來是在藍玫瑰島見過的人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이에 어울리지 않게 대단한 실력이라고 생각했는데, 아카데미에서 다시 만나다니 기쁘네요.  ","JPN":"その年齢にしてはすごい実力だと思いましたが、アカデミーでまたお会いできて嬉しいです。 ","ENG":"I was impressed by how capable you are at your age. It's great to see you again at the Academy.  ","TWN":"當時就覺得你實力不簡單，能在學院再次見面我很高興。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으응, 그렇지. 뭐. 그때는 갑판 청소부 신세였지만.","JPN":"あ、まあね。あの時はただの甲板掃除担当だったけどね。","ENG":"Yeah, I guess. Thanks. Then again, I was just a deck janitor back then.","TWN":"嗯。當時我只是充當甲板清道夫而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 저희한테는 무슨 일이세요, 회장님?","JPN":"ところで、私たちに何かご用ですか、会長？","ENG":"How may we help you, Ms. President?","TWN":"你來找我們有什麼事，會長？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다른 학생들에게서 들어오는 항의를 해결하러 왔어요.","JPN":"他の生徒から苦情を受けて話に参りました。","ENG":"I've come to sort out a complaint lodged by other students.","TWN":"我是來解決其他學生提出的抗議的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분이 침식체를 너무 많이 격퇴하는 바람에 다른 학생들이 훈련을 진행하지 못하는 상태라더군요.","JPN":"皆さんがこの辺の侵食体を倒しすぎて、他の生徒の訓練が進まない状況らしいです。","ENG":"They're saying they cannot train because your squad has been killing all the C.O.s.","TWN":"因為三位消滅的侵蝕體太多，其他學生現在沒辦法進行訓練了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"회장님, 그게 무슨 말씀이세요!","JPN":"会長、それは理不尽です！","ENG":"But that's absurd!","TWN":"會長，你怎麼可以這麼說呢！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"훈련도 마술도 최선을 다하지 않으면 안 되는 법이잖아요!","JPN":"訓練もマジックも最善を尽くしてやらなければならないでしょう？","ENG":"We should always try our best, whether it's training or magic tricks!","TWN":"訓練也好，魔術也好，都要盡全力才行啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"틀린 말은 아니지만, 학생들에게 공평한 기회를 주는 것 역시 학생회장의 본분이에요.","JPN":"間違ってはいませんが、生徒に公平な機会を与えることも生徒会長の本分です。","ENG":"I don't disagree, but as Student President, I'm also responsible for giving everyone a fair shot.","TWN":"你說的沒錯，但是我也得給其他學生公平的機會，這也是學生會長的本職工作。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};